import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { AdminLayout } from './components/admin/AdminLayout';
import { AdminArtists } from './pages/admin/artists/AdminArtists';
import { AdminArtistsForm } from './pages/admin/artists/AdminArtistsForm';
import { AdminTaxonomy } from './pages/admin/taxonomy/AdminTaxonomy';

function App() {
  return (
    <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
      <Routes>
        {/* Main Website */}
        <Route path="/" element={<div className="p-20 text-center font-serif italic text-4xl">Atlal Archive Under Construction</div>} />

        {/* Admin Dashboard */}
        <Route path="/admin" element={<AdminLayout />}>
          <Route index element={<div className="text-white p-10">Welcome to the Control Room</div>} />
          <Route path="artists" element={<AdminArtists />} />
          <Route path="artists/new" element={<AdminArtistsForm />} />
          <Route path="taxonomy" element={<AdminTaxonomy />} />
        </Route>
      </Routes>
    </Router>
  );
}

export default App;
